import React, { Component } from "react";
import ProjectDetailsModal from "./ProjectDetailsModal";
import { motion } from "framer-motion";

class Projects extends Component {
  constructor(props) {
    super(props);
    this.state = {
      deps: {},
      detailsModalShow: false,
      visibleItems: []
    };

    this.projectRefs = [];
  }

  componentDidMount() {
    this.observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            const index = Number(entry.target.getAttribute("data-index"));
            this.setState((prevState) => ({
              visibleItems: [...new Set([...prevState.visibleItems, index])]
            }));
          }
        });
      },
      { threshold: 0.2 }
    );

    this.projectRefs.forEach((ref) => {
      if (ref) this.observer.observe(ref);
    });
  }

  componentWillUnmount() {
    if (this.observer) {
      this.projectRefs.forEach((ref) => {
        if (ref) this.observer.unobserve(ref);
      });
    }
  }

  render() {
    let detailsModalShow = (data) => {
      this.setState({ detailsModalShow: true, deps: data });
    };

    let detailsModalClose = () =>
      this.setState({ detailsModalShow: false });

    const fadeUp = {
      hidden: { opacity: 0, y: 40 },
      visible: { opacity: 1, y: 0 }
    };

    if (this.props.resumeProjects && this.props.resumeBasicInfo) {
      var sectionName = this.props.resumeBasicInfo.section_name.projects;

      var projects = this.props.resumeProjects.map((projects, i) => {
        const isVisible = this.state.visibleItems.includes(i);

        return (
          <motion.div
            ref={(el) => (this.projectRefs[i] = el)}
            data-index={i}
            className="col-sm-12 col-md-6 col-lg-4"
            key={projects.title}
            style={{ cursor: "pointer" }}
            variants={fadeUp}
            // initial="hidden"
            // animate={isVisible ? "visible" : "hidden"}
            initial={{ opacity: 0, y: 40 }}
            animate={
              isVisible
                ? { opacity: 1, y: 0 }
                : { opacity: 0.3, y: 20 }
            }
            transition={{ duration: 0.6, delay: i * 0.1 }}
          >
            <span className="portfolio-item d-block">
              <div
                className="foto"
                onClick={() => detailsModalShow(projects)}
              >
                <div
                  style={{
                    height: "230px",
                    padding: "15px",
                    display: "flex",
                    flexDirection: "column",
                    justifyContent: "flex-start",
                    borderRadius: "8px"
                  }}
                >
                  {/* Date */}
                  <span className="project-date">
                    {projects.startDate}
                  </span>

                  {/* Title */}
                  <p className="project-title-settings mt-2">
                    {projects.title}
                  </p>

                  {/* Description */}
                  <p
                    style={{
                      fontSize: "14px",
                      textAlign: "justify",
                      marginTop: "10px",
                      overflow: "hidden"
                    }}
                  >
                    {projects.description}
                  </p>
                </div>
              </div>
            </span>
          </motion.div>
        );
      });
    }

    return (
      <section id="portfolio">
        <div className="col-md-12">
          <h1 className="section-title" style={{ color: "black" }}>
            <span>{sectionName}</span>
          </h1>

          <div className="col-md-12 mx-auto">
            <div className="row mx-auto">{projects}</div>
          </div>

          <ProjectDetailsModal
            show={this.state.detailsModalShow}
            onHide={detailsModalClose}
            data={this.state.deps}
          />
        </div>
      </section>
    );
  }
}

export default Projects;
